import numpy as np
from scipy import ndimage

def solve(grid):
    grid = np.array(grid)
    H, W = grid.shape
    bg = int(grid[0, 0])

    # Find frames
    colors = set(int(x) for x in np.unique(grid)) - {bg}
    frames = []

    for color in colors:
        mask = (grid == color)
        labeled, num = ndimage.label(mask)
        for i in range(1, num + 1):
            rows, cols = np.where(labeled == i)
            r_min, r_max = int(rows.min()), int(rows.max())
            c_min, c_max = int(cols.min()), int(cols.max())
            height = r_max - r_min + 1
            width = c_max - c_min + 1

            if height < 4 or width < 4:
                continue

            # Check border
            is_frame = True
            for r in range(r_min, r_max + 1):
                if grid[r, c_min] != color or grid[r, c_max] != color:
                    is_frame = False
                    break
            if is_frame:
                for c in range(c_min, c_max + 1):
                    if grid[r_min, c] != color or grid[r_max, c] != color:
                        is_frame = False
                        break
            if is_frame:
                # Check interior is bg
                interior_bg = True
                for r in range(r_min + 1, r_max):
                    for c in range(c_min + 1, c_max):
                        if grid[r, c] != bg:
                            interior_bg = False
                            break
                    if not interior_bg:
                        break

                if interior_bg:
                    cells = set(zip(rows.tolist(), cols.tolist()))
                    frames.append({
                        'color': color,
                        'r_min': r_min, 'r_max': r_max,
                        'c_min': c_min, 'c_max': c_max,
                        'cells': cells
                    })

    # Collect all frame cells
    all_frame_cells = set()
    for f in frames:
        all_frame_cells |= f['cells']

    # Build output - start with background
    out = np.full_like(grid, bg)

    # Draw frames
    for f in frames:
        for r, c in f['cells']:
            out[r, c] = f['color']

    # For each frame, count same-color components outside frames
    for f in frames:
        color = f['color']
        mask = np.zeros((H, W), dtype=bool)
        for r in range(H):
            for c in range(W):
                if int(grid[r, c]) == color and (r, c) not in all_frame_cells:
                    mask[r, c] = True
        _, num = ndimage.label(mask)

        if num > 0:
            interior_h = f['r_max'] - f['r_min'] - 1
            interior_w = f['c_max'] - f['c_min'] - 1
            mid_row = f['r_min'] + 1 + interior_h // 2

            for i in range(1, num + 1):
                col = f['c_min'] + 1 + (interior_w - 2 * i)
                if col >= f['c_min'] + 1:
                    out[mid_row, col] = color

    return out.tolist()

