    frames = []

    for color in colors:
        mask = (grid == color)
        labeled, num = ndimage.label(mask)
        for i in range(1, num + 1):
            rows, cols = np.where(labeled == i)
            r_min, r_max = int(rows.min()), int(rows.max())
            c_min, c_max = int(cols.min()), int(cols.max())
            height = r_max - r_min + 1
            width = c_max - c_min + 1

            if height < 4 or width < 4:
                continue

            # Check border
            is_frame = True
            for r in range(r_min, r_max + 1):
                if grid[r, c_min] != color or grid[r, c_max] != color:
                    is_frame = False
                    break
            if is_frame:
                for c in range(c_min, c_max + 1):
                    if grid[r_min, c] != color or grid[r_max, c] != color:
                        is_frame = False
                        break
            if is_frame:
                # Check interior is bg
                interior_bg = True
                for r in range(r_min + 1, r_max):
                    for c in range(c_min + 1, c_max):
                        if grid[r, c] != bg:
                            interior_bg = False
                            break
                    if not interior_bg:
                        break

                if interior_bg:
                    cells = set(zip(rows.tolist(), cols.tolist()))
                    frames.append({
                        'color': color,
                        'r_min': r_min, 'r_max': r_max,
                        'c_min': c_min, 'c_max': c_max,
                        'cells': cells
                    })

    # Collect all frame cells
    all_frame_cells = set()
    for f in frames:
        all_frame_cells |= f['cells']

    # Build output - start with background
